def generate_jwt(payload, secret_key):
    try:
        exp = datetime.utcnow() + timedelta(minutes=30)
        payload['exp'] = exp
        token = jwt.encode(payload, secret_key, algorithm='HS256')
        return token
    except Exception as e:
        print(f"Error generating JWT: {str(e)}")
